"use client";

import { useEffect, useMemo, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Search,
  MoreVertical,
  Plus,
  Mail,
  Phone,
  CheckCircle2,
  XCircle,
  Clock,
} from "lucide-react";
import { useToast } from "@/components/ui/use-toast";
import { cn } from "@/lib/utils";
import {
  defaultProviders,
  PROVIDERS_STORAGE_KEY,
  type Provider,
  type ProviderStatus,
} from "../provider-data";

const getStatusBadge = (status: ProviderStatus) => {
  const styles = {
    active: "bg-green-100 text-green-700 dark:bg-green-900/20 dark:text-green-400",
    inactive: "bg-gray-100 text-gray-700 dark:bg-gray-900/20 dark:text-gray-400",
    suspended: "bg-red-100 text-red-700 dark:bg-red-900/20 dark:text-red-400",
  } as const;

  const icons = {
    active: CheckCircle2,
    inactive: Clock,
    suspended: XCircle,
  } as const;

  const Icon = icons[status];

  return (
    <Badge
      variant="outline"
      className={styles[status]}
    >
      <Icon className="h-3 w-3 mr-1" />
      {status.charAt(0).toUpperCase() + status.slice(1)}
    </Badge>
  );
};

const getInitialProviderForm = () => ({
  name: "",
  email: "",
  phone: "",
  specialization: "",
  rating: "",
  completedJobs: "",
  status: "active" as ProviderStatus,
  joinedDate: new Date().toISOString().slice(0, 10),
});

const ProvidersManagePage = () => {
  const [searchQuery, setSearchQuery] = useState("");
  const [providers, setProviders] = useState<Provider[]>(defaultProviders);
  const [showAddProvider, setShowAddProvider] = useState(false);
  const [newProvider, setNewProvider] = useState(getInitialProviderForm());
  const { toast } = useToast();

  useEffect(() => {
    if (typeof window === "undefined") return;

    const stored = localStorage.getItem(PROVIDERS_STORAGE_KEY);
    if (stored) {
      try {
        const parsed = JSON.parse(stored) as Provider[];
        if (Array.isArray(parsed) && parsed.length > 0) {
          setProviders(parsed);
        }
      } catch (error) {
        console.error("Failed to parse stored providers", error);
      }
    }
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;
    localStorage.setItem(PROVIDERS_STORAGE_KEY, JSON.stringify(providers));
  }, [providers]);

  const filteredProviders = useMemo(() => {
    const query = searchQuery.toLowerCase();
    return providers.filter(
      (provider) =>
        provider.name.toLowerCase().includes(query) ||
        provider.email.toLowerCase().includes(query) ||
        provider.specialization.toLowerCase().includes(query)
    );
  }, [providers, searchQuery]);

  const handleAddProvider = () => {
    if (!newProvider.name || !newProvider.email || !newProvider.phone || !newProvider.specialization) {
      toast({
        title: "Missing information",
        description: "Please fill in the required fields (name, email, phone, specialization).",
        variant: "destructive",
      });
      return;
    }

    const provider: Provider = {
      id: `PRV${Date.now()}`,
      name: newProvider.name,
      email: newProvider.email,
      phone: newProvider.phone,
      specialization: newProvider.specialization,
      rating: newProvider.rating ? Number.parseFloat(newProvider.rating) : 0,
      completedJobs: newProvider.completedJobs ? Number.parseInt(newProvider.completedJobs, 10) : 0,
      status: newProvider.status,
      joinedDate: newProvider.joinedDate || new Date().toISOString().slice(0, 10),
    };

    setProviders((prev) => [provider, ...prev]);
    setNewProvider(getInitialProviderForm());
    setShowAddProvider(false);

    toast({
      title: "Provider added",
      description: `${provider.name} was added successfully.`,
    });
  };

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
            <CardTitle>Service Providers</CardTitle>
            <div className="flex gap-3">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Search providers..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-9 w-full md:w-64"
                />
              </div>
              <Button
                className="text-white"
                style={{ background: "linear-gradient(135deg, #00BCD4 0%, #00D4E8 100%)" }}
                onClick={() => setShowAddProvider(true)}
              >
                <Plus className="h-4 w-4 mr-2" />
                Add Provider
              </Button>
            </div>
          </div>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Name</TableHead>
                <TableHead>Contact</TableHead>
                <TableHead>Specialization</TableHead>
                <TableHead>Rating</TableHead>
                <TableHead>Completed Jobs</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredProviders.map((provider) => (
                <TableRow key={provider.id}>
                  <TableCell>
                    <div className="flex items-center gap-2">
                      <div className="h-8 w-8 rounded-full bg-gradient-to-br from-cyan-400 to-blue-500 flex items-center justify-center text-white font-semibold text-sm">
                        {provider.name
                          .split(" ")
                          .map((n) => n[0])
                          .join("")}
                      </div>
                      <span className="font-medium">{provider.name}</span>
                    </div>
                  </TableCell>
                  <TableCell>
                    <div className="space-y-1">
                      <div className="flex items-center gap-1 text-sm">
                        <Mail className="h-3 w-3 text-muted-foreground" />
                        <span className="text-muted-foreground">{provider.email}</span>
                      </div>
                      <div className="flex items-center gap-1 text-sm">
                        <Phone className="h-3 w-3 text-muted-foreground" />
                        <span className="text-muted-foreground">{provider.phone}</span>
                      </div>
                    </div>
                  </TableCell>
                  <TableCell>
                    <Badge variant="secondary">{provider.specialization}</Badge>
                  </TableCell>
                  <TableCell>{provider.rating.toFixed(1)}</TableCell>
                  <TableCell>{provider.completedJobs}</TableCell>
                  <TableCell>{getStatusBadge(provider.status)}</TableCell>
                  <TableCell className="text-right">
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button variant="ghost" size="icon">
                          <MoreVertical className="h-4 w-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuLabel>Actions</DropdownMenuLabel>
                        <DropdownMenuSeparator />
                        <DropdownMenuItem>View Details</DropdownMenuItem>
                        <DropdownMenuItem>Edit Provider</DropdownMenuItem>
                        <DropdownMenuItem>View Jobs</DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuItem className="text-red-600">
                          Suspend Provider
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      <Dialog open={showAddProvider} onOpenChange={setShowAddProvider}>
        <DialogContent className="max-w-xl">
          <DialogHeader>
            <DialogTitle>Add Service Provider</DialogTitle>
            <DialogDescription>
              Enter provider details. The provider will be saved for future sessions.
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4">
            <div className="grid gap-3">
              <div>
                <label className="text-sm font-medium mb-1 block">Full Name *</label>
                <Input
                  placeholder="Enter provider name"
                  value={newProvider.name}
                  onChange={(e) => setNewProvider((prev) => ({ ...prev, name: e.target.value }))}
                />
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <div>
                  <label className="text-sm font-medium mb-1 block">Email *</label>
                  <Input
                    type="email"
                    placeholder="provider@example.com"
                    value={newProvider.email}
                    onChange={(e) => setNewProvider((prev) => ({ ...prev, email: e.target.value }))}
                  />
                </div>
                <div>
                  <label className="text-sm font-medium mb-1 block">Phone *</label>
                  <Input
                    placeholder="(555) 123-4567"
                    value={newProvider.phone}
                    onChange={(e) => setNewProvider((prev) => ({ ...prev, phone: e.target.value }))}
                  />
                </div>
              </div>
              <div>
                <label className="text-sm font-medium mb-1 block">Specialization *</label>
                <Input
                  placeholder="e.g. Deep Cleaning"
                  value={newProvider.specialization}
                  onChange={(e) => setNewProvider((prev) => ({ ...prev, specialization: e.target.value }))}
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <div>
                <label className="text-sm font-medium mb-1 block">Rating</label>
                <Input
                  type="number"
                  min="0"
                  max="5"
                  step="0.1"
                  placeholder="4.8"
                  value={newProvider.rating}
                  onChange={(e) => setNewProvider((prev) => ({ ...prev, rating: e.target.value }))}
                />
              </div>
              <div>
                <label className="text-sm font-medium mb-1 block">Completed Jobs</label>
                <Input
                  type="number"
                  min="0"
                  placeholder="150"
                  value={newProvider.completedJobs}
                  onChange={(e) => setNewProvider((prev) => ({ ...prev, completedJobs: e.target.value }))}
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <div>
                <label className="text-sm font-medium mb-1 block">Status</label>
                <Select
                  value={newProvider.status}
                  onValueChange={(value: ProviderStatus) => setNewProvider((prev) => ({ ...prev, status: value }))}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select status" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="active">Active</SelectItem>
                    <SelectItem value="inactive">Inactive</SelectItem>
                    <SelectItem value="suspended">Suspended</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <label className="text-sm font-medium mb-1 block">Joined Date</label>
                <Input
                  type="date"
                  value={newProvider.joinedDate}
                  onChange={(e) => setNewProvider((prev) => ({ ...prev, joinedDate: e.target.value }))}
                />
              </div>
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setShowAddProvider(false)}>
              Cancel
            </Button>
            <Button
              className="text-white"
              style={{ background: "linear-gradient(135deg, #00BCD4 0%, #00D4E8 100%)" }}
              onClick={handleAddProvider}
            >
              Save Provider
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default ProvidersManagePage;
